import React, { useCallback, useEffect, useState } from "react";
import {
  UserPlus,
  Plus,
  Trash2,
  KeyRound,
  Search,
  X,
  CheckCircle,
  AlertCircle,
  UserMinus,
} from "lucide-react";
import api from "../../api.js";
import "../../components/Components.css";
import "../dashboard/Dashboard.css";

const ROLE_COLORS = {
  Lead_Investigator: { color: "#34d399", bg: "rgba(52,211,153,0.1)" },
  Forensic_Officer: { color: "#fbbf24", bg: "rgba(251,191,36,0.1)" },
  Police_Officer: { color: "#60a5fa", bg: "rgba(96,165,250,0.1)" },
  Supervising_Officer: { color: "#818cf8", bg: "rgba(129,140,248,0.1)" },
  Administrator: { color: "#a78bfa", bg: "rgba(167,139,250,0.1)" },
};

const ROLES = [
  "Lead_Investigator",
  "Forensic_Officer",
  "Police_Officer",
  "Supervising_Officer",
];

const DEFAULT_MEMBER_PASSWORD = "pass123";

function buildGeneratedEmail(name = "") {
  const slug = name
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");

  return slug ? `${slug}@gmail.com` : "";
}

export default function MembersPage() {
  const [users, setUsers] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState({ type: "", text: "" });

  // Add member form
  const [showAddForm, setShowAddForm] = useState(false);
  const [newUser, setNewUser] = useState({
    name: "",
    email: "",
    role_name: "Police_Officer",
    Region: "",
    password: DEFAULT_MEMBER_PASSWORD,
  });
  const [adding, setAdding] = useState(false);

  // Reset password modal
  const [resetTarget, setResetTarget] = useState(null); // { _id, name }
  const [newPassword, setNewPassword] = useState("");
  const [resetting, setResetting] = useState(false);
  const [assignTarget, setAssignTarget] = useState(null);
  const [assigning, setAssigning] = useState(false);
  const [assignMsg, setAssignMsg] = useState({ type: "", text: "" });
  const [selectedCase, setSelectedCase] = useState("");
  const [caseList, setCaseList] = useState([]);

  const flash = (type, text) => {
    setMsg({ type, text });
    setTimeout(() => setMsg({ type: "", text: "" }), 4000);
  };

  const fetchUsers = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get("/users");
      setUsers(Array.isArray(res.data) ? res.data : []);
    } catch {
      flash("error", "Failed to load members");
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchCases = useCallback(async () => {
    try {
      const res = await api.get("/all-cases");
      setCaseList(Array.isArray(res.data) ? res.data : []);
    } catch {
      flash("error", "Unable to load case list");
    }
  }, []);

  useEffect(() => {
    fetchUsers();
  }, [fetchUsers]);

  useEffect(() => {
    if (assignTarget) {
      setAssignMsg({ type: "", text: "" });
      fetchCases();
    }
  }, [assignTarget, fetchCases]);

  // Client-side search filter
  useEffect(() => {
    if (!search) {
      setFiltered(users);
    } else {
      const lower = search.toLowerCase();
      setFiltered(
        users.filter(
          (u) =>
            u.name?.toLowerCase().includes(lower) ||
            u.email?.toLowerCase().includes(lower) ||
            u.role_id?.role_name?.toLowerCase().includes(lower),
        ),
      );
    }
  }, [search, users]);

  // Create a new member
  const handleAddMember = async () => {
    if (!newUser.name.trim() || !newUser.email.trim())
      return flash("error", "Name and email are required");

    setAdding(true);
    try {
      await api.post("/users/create", {
        name: newUser.name.trim(),
        email: newUser.email.trim(),
        role_name: newUser.role_name,
        Region: newUser.Region.trim(),
        password: newUser.password.trim() || DEFAULT_MEMBER_PASSWORD,
      });
      flash("success", `Member "${newUser.name}" created successfully`);
      setNewUser({
        name: "",
        email: "",
        role_name: "Police_Officer",
        Region: "",
        password: DEFAULT_MEMBER_PASSWORD,
      });
      setShowAddForm(false);
      fetchUsers();
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to create member");
    } finally {
      setAdding(false);
    }
  };

  // Delete a member
  const handleDelete = async (userId, name) => {
    if (
      !window.confirm(
        `Permanently delete "${name}" from the system? This cannot be undone.`,
      )
    )
      return;
    try {
      await api.delete(`/users/${userId}`);
      flash("success", `"${name}" has been deleted`);
      setUsers((prev) => prev.filter((u) => u._id !== userId));
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to delete member");
    }
  };

  // Remove from all cases (keep account)
  const handleRemoveFromCases = async (userId, name) => {
    if (
      !window.confirm(
        `Remove "${name}" from all cases? Their account will remain.`,
      )
    )
      return;
    try {
      await api.delete(`/users/${userId}/cases`);
      flash("success", `"${name}" removed from all cases`);
    } catch (err) {
      flash(
        "error",
        err.response?.data?.message || "Failed to remove from cases",
      );
    }
  };

  const handleAssignCase = async () => {
    if (!selectedCase || !assignTarget) {
      setAssignMsg({ type: "error", text: "Select a case before assigning." });
      return flash("error", "Select a case before assigning");
    }
    setAssigning(true);
    try {
      await api.post(`/case/${selectedCase}/member`, {
        user_id: assignTarget._id,
      });
      setAssignMsg({
        type: "success",
        text: `${assignTarget.name} assigned successfully.`,
      });
      flash("success", `${assignTarget.name} has been assigned to the case`);
      await fetchUsers();
      setTimeout(() => {
        setAssignTarget(null);
        setSelectedCase("");
        setAssignMsg({ type: "", text: "" });
      }, 900);
    } catch (err) {
      setAssignMsg({
        type: "error",
        text: err.response?.data?.message || "Failed to assign member to case",
      });
      flash(
        "error",
        err.response?.data?.message || "Failed to assign member to case",
      );
    } finally {
      setAssigning(false);
    }
  };

  // Reset password
  const handleResetPassword = async () => {
    if (!newPassword || newPassword.length < 6)
      return flash("error", "Password must be at least 6 characters");
    setResetting(true);
    try {
      await api.post(`/users/${resetTarget._id}/reset-password`, {
        newPassword,
      });
      flash(
        "success",
        `Password reset for "${resetTarget.name}". They have been notified.`,
      );
      setResetTarget(null);
      setNewPassword("");
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to reset password");
    } finally {
      setResetting(false);
    }
  };

  const getRoleStyle = (roleName) =>
    ROLE_COLORS[roleName] || { color: "#94a3b8", bg: "rgba(148,163,184,0.1)" };

  return (
    <div className="dashboardMain">
      {/* Header */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText">
            <span>LEGALLENS</span> Members
          </h1>
          <p className="systemStatus">
            Manage system users •{" "}
            <span className="highlightText">{users.length} total members</span>
          </p>
        </div>
        <button
          type="button"
          className="primaryActionBtn"
          style={{ width: "auto", padding: "0.75rem 1.5rem" }}
          onClick={() => setShowAddForm((v) => !v)}
        >
          {showAddForm ? (
            <>
              <X size={16} /> Cancel
            </>
          ) : (
            <>
              <UserPlus size={16} /> Add Member
            </>
          )}
        </button>
      </header>

      {/* Alert */}
      {msg.text && (
        <div
          className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.5rem",
            marginBottom: "1.5rem",
          }}
        >
          {msg.type === "success" ? (
            <CheckCircle size={16} />
          ) : (
            <AlertCircle size={16} />
          )}
          {msg.text}
        </div>
      )}

      {/* Add Member Form */}
      {showAddForm && (
        <div className="formSectionCard" style={{ marginBottom: "1.5rem" }}>
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background: "#34d399" }} />
            <h2>NEW MEMBER</h2>
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "1rem",
              padding: "1.5rem",
            }}
          >
            <div className="inputGroup">
              <label>Full Name *</label>
              <input
                type="text"
                placeholder="e.g. John Smith"
                value={newUser.name}
                onChange={(e) =>
                  setNewUser((p) => {
                    const nextName = e.target.value;
                    const previousGeneratedEmail = buildGeneratedEmail(p.name);
                    const nextGeneratedEmail = buildGeneratedEmail(nextName);
                    const shouldAutoUpdateEmail =
                      !p.email || p.email === previousGeneratedEmail;

                    return {
                      ...p,
                      name: nextName,
                      email: shouldAutoUpdateEmail
                        ? nextGeneratedEmail
                        : p.email,
                    };
                  })
                }
              />
            </div>
            <div className="inputGroup">
              <label>Email Address *</label>
              <input
                type="email"
                placeholder="john-smith@gmail.com"
                value={newUser.email}
                onChange={(e) =>
                  setNewUser((p) => ({ ...p, email: e.target.value }))
                }
              />
            </div>
            <div className="inputGroup">
              <label>Role</label>
              <select
                value={newUser.role_name}
                onChange={(e) =>
                  setNewUser((p) => ({ ...p, role_name: e.target.value }))
                }
                style={{
                  background: "#1e293b",
                  border: "1px solid rgba(255,255,255,0.08)",
                  color: "#fff",
                  padding: "0.75rem 1rem",
                  borderRadius: 8,
                  fontSize: "0.9rem",
                  width: "100%",
                }}
              >
                {ROLES.map((r) => (
                  <option key={r} value={r}>
                    {r.replace(/_/g, " ")}
                  </option>
                ))}
              </select>
            </div>
            <div className="inputGroup">
              <label>Region</label>
              <input
                type="text"
                placeholder="e.g. North District"
                value={newUser.Region}
                onChange={(e) =>
                  setNewUser((p) => ({ ...p, Region: e.target.value }))
                }
              />
            </div>
            <div className="inputGroup" style={{ gridColumn: "span 2" }}>
              <label>Temporary Password (default: pass123)</label>
              <input
                type="text"
                placeholder="Leave blank to use default"
                value={newUser.password}
                onChange={(e) =>
                  setNewUser((p) => ({ ...p, password: e.target.value }))
                }
              />
            </div>
          </div>
          <div
            style={{
              padding: "0 1.5rem 1.5rem",
              display: "flex",
              gap: "1rem",
              justifyContent: "flex-end",
            }}
          >
            <button
              type="button"
              className="btnCancel"
              onClick={() => setShowAddForm(false)}
            >
              Cancel
            </button>
            <button
              type="button"
              className="btnCreate"
              onClick={handleAddMember}
              disabled={adding}
            >
              {adding ? (
                "Creating..."
              ) : (
                <>
                  <UserPlus size={15} style={{ marginRight: 6 }} />
                  Create Member
                </>
              )}
            </button>
          </div>
        </div>
      )}

      {/* Members Table */}
      <div className="formSectionCard">
        <div className="sectionHeader">
          <div className="indicatorDot" />
          <h2>SYSTEM MEMBERS</h2>
          <div style={{ marginLeft: "auto" }}>
            <div className="membersSearch" style={{ maxWidth: 340 }}>
              <Search size={16} color="#475569" />
              <input
                type="text"
                placeholder="Search by name, email or role..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                style={{
                  background: "transparent",
                  border: "none",
                  outline: "none",
                  color: "#fff",
                  fontSize: "0.875rem",
                  flex: 1,
                }}
              />
              {search && (
                <button
                  type="button"
                  onClick={() => setSearch("")}
                  style={{
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                    color: "#64748b",
                    display: "flex",
                  }}
                >
                  <X size={14} />
                </button>
              )}
            </div>
          </div>
        </div>

        <table className="legalTable">
          <thead>
            <tr>
              <th>Member</th>
              <th>Role</th>
              <th>Region</th>
              <th>Email</th>
              <th style={{ textAlign: "right" }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td
                  colSpan={5}
                  style={{
                    textAlign: "center",
                    padding: "3rem",
                    color: "#475569",
                  }}
                >
                  <div
                    className="miniSpinner"
                    style={{ margin: "0 auto 0.75rem" }}
                  />
                  Loading members...
                </td>
              </tr>
            ) : filtered.length === 0 ? (
              <tr>
                <td
                  colSpan={5}
                  style={{
                    textAlign: "center",
                    padding: "3rem",
                    color: "#475569",
                  }}
                >
                  {search
                    ? `No members matching "${search}"`
                    : "No members found"}
                </td>
              </tr>
            ) : (
              filtered.map((u) => {
                const roleName = u.role_id?.role_name || "Unknown";
                const roleStyle = getRoleStyle(roleName);
                return (
                  <tr key={u._id} className="auditRow">
                    <td>
                      <div className="nameCell">
                        <div className="avatarCircle">
                          {u.name?.charAt(0)?.toUpperCase()}
                        </div>
                        <div>
                          <p
                            className="boldText"
                            style={{ margin: 0, fontSize: "0.875rem" }}
                          >
                            {u.name}
                          </p>
                        </div>
                      </div>
                    </td>
                    <td>
                      <span
                        style={{
                          background: roleStyle.bg,
                          color: roleStyle.color,
                          padding: "3px 10px",
                          borderRadius: 6,
                          fontSize: "11px",
                          fontWeight: 700,
                        }}
                      >
                        {roleName.replace(/_/g, " ")}
                      </span>
                    </td>
                    <td className="mutedText" style={{ fontSize: "0.8rem" }}>
                      {u.Region || "—"}
                    </td>
                    <td className="mutedText" style={{ fontSize: "0.8rem" }}>
                      {u.email}
                    </td>
                    <td>
                      <div
                        style={{
                          display: "flex",
                          gap: "0.5rem",
                          justifyContent: "flex-end",
                        }}
                      >
                        {/* Reset Password */}
                        <button
                          type="button"
                          className="actionCircle"
                          title="Reset password"
                          style={{ color: "#fbbf24" }}
                          onClick={() => {
                            setResetTarget({ _id: u._id, name: u.name });
                            setNewPassword("");
                          }}
                        >
                          <KeyRound size={15} />
                        </button>

                        {/* Remove from all cases */}
                        <button
                          type="button"
                          className="actionCircle"
                          title="Remove from all cases"
                          style={{ color: "#f87171" }}
                          onClick={() => handleRemoveFromCases(u._id, u.name)}
                        >
                          <UserMinus size={15} />
                        </button>

                        {/* Delete from system */}
                        <button
                          type="button"
                          className="actionCircle"
                          title="Assign to case"
                          style={{ color: "#60a5fa" }}
                          onClick={() => setAssignTarget(u)}
                        >
                          <Plus size={15} />
                        </button>
                        <button
                          type="button"
                          className="actionCircle"
                          title="Delete from system"
                          style={{ color: "#f87171" }}
                          onClick={() => handleDelete(u._id, u.name)}
                        >
                          <Trash2 size={15} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>

      {assignTarget && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.8)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
          onClick={() => setAssignTarget(null)}
        >
          <div
            style={{
              background: "#0f172a",
              border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 12,
              padding: "2rem",
              width: "100%",
              maxWidth: 520,
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                marginBottom: "1.5rem",
              }}
            >
              <div>
                <h3 style={{ margin: 0, color: "#fff", fontSize: "1.1rem" }}>
                  Assign {assignTarget.name} to a Case
                </h3>
                <p
                  style={{
                    margin: "0.5rem 0 0",
                    color: "#94a3b8",
                    fontSize: "0.9rem",
                  }}
                >
                  Choose a case to assign this member to and notify the team.
                </p>
              </div>
              <button
                type="button"
                onClick={() => setAssignTarget(null)}
                style={{
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  color: "#64748b",
                }}
              >
                <X size={18} />
              </button>
            </div>
            <div className="inputGroup" style={{ marginBottom: "1.5rem" }}>
              <label>Select Case</label>
              <select
                value={selectedCase}
                onChange={(e) => setSelectedCase(e.target.value)}
                style={{
                  background: "#1e293b",
                  border: "1px solid rgba(255,255,255,0.08)",
                  color: "#fff",
                  padding: "0.75rem 1rem",
                  borderRadius: 8,
                  fontSize: "0.9rem",
                  width: "100%",
                }}
              >
                <option value="">— Select a case —</option>
                {caseList.map((caseItem) => (
                  <option key={caseItem._id || caseItem.id} value={caseItem.case_id}>
                    #{caseItem.case_id} — {caseItem.title}
                  </option>
                ))}
              </select>
            </div>
            {assignMsg.text && (
              <div
                className={`alertBanner ${assignMsg.type === "success" ? "alertSuccess" : "alertError"}`}
                style={{ marginBottom: "1.25rem" }}
              >
                {assignMsg.text}
              </div>
            )}
            <div
              style={{
                display: "flex",
                gap: "1rem",
                justifyContent: "flex-end",
              }}
            >
              <button
                type="button"
                className="btnCancel"
                onClick={() => setAssignTarget(null)}
              >
                Cancel
              </button>
              <button
                type="button"
                className="btnCreate"
                onClick={handleAssignCase}
                disabled={assigning}
              >
                {assigning ? "Assigning..." : "Assign to Case"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Reset Password Modal */}
      {resetTarget && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.7)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
        >
          <div
            style={{
              background: "#0f172a",
              border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 12,
              padding: "2rem",
              width: "100%",
              maxWidth: 420,
            }}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                marginBottom: "1.5rem",
              }}
            >
              <h3 style={{ margin: 0, color: "#fff", fontSize: "1.1rem" }}>
                Reset Password for {resetTarget.name}
              </h3>
              <button
                type="button"
                onClick={() => {
                  setResetTarget(null);
                  setNewPassword("");
                }}
                style={{
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  color: "#64748b",
                }}
              >
                <X size={18} />
              </button>
            </div>

            <p
              style={{
                color: "#64748b",
                fontSize: "0.85rem",
                marginBottom: "1.25rem",
              }}
            >
              The member will be notified with their new password via the
              notification system.
            </p>

            <div className="inputGroup" style={{ marginBottom: "1.5rem" }}>
              <label>New Password (min 6 characters)</label>
              <input
                type="text"
                placeholder="Enter new password"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
                autoFocus
              />
            </div>

            <div
              style={{
                display: "flex",
                gap: "1rem",
                justifyContent: "flex-end",
              }}
            >
              <button
                type="button"
                className="btnCancel"
                onClick={() => {
                  setResetTarget(null);
                  setNewPassword("");
                }}
              >
                Cancel
              </button>
              <button
                type="button"
                className="btnCreate"
                onClick={handleResetPassword}
                disabled={resetting}
              >
                {resetting ? (
                  "Resetting..."
                ) : (
                  <>
                    <KeyRound size={15} style={{ marginRight: 6 }} />
                    Reset Password
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
